package entity_test

import (
	"testing"

	"github.com/yourorg/beanbrew/internal/entity"
)

// TestUnitOrderCalculateTotalEdgeCases – дополнительные edge‑case‑тесты
// для метода Order.CalculateTotal().  В проекте уже есть
// TestUnitOrderCalculateTotal и TestUnitOrderCalculateTotalEmpty, поэтому
// здесь проверяем сценарии, которые пока не покрыты:
//
//   1. Товар с нулевой ценой – итог должен игнорировать цену.
//   2. Товар с нулевым количеством – тоже не вносит вклад в сумму.
//   3. Очень большие цены/количества (проверка на отсутствие переполнения
//      int64/float64, в зависимости от реализации).  Мы используем int64
//      для цены и количества, а итог хранится в int64, поэтому проверяем
//      границу 2 147 483 647 (max int32) и 9 223 372 036 854 775 807 (max int64).
//   4. Несколько позиций, где одна из них имеет нулевую цену, а другая –
//      обычную цену; итог должен учитывать только «рабочие» позиции.
//   5. Дублирование товаров (один и тот же ProductID в разных позициях) –
//      метод не делает никаких предположений о уникальности, просто суммирует.
//
// Тест построен как table‑driven, каждый кейс – отдельный sub‑test
// (t.Run), что соответствует общему паттерну проекта.

func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	type testCase struct {
		name     string
		items    []entity.OrderItem
		expected int64 // ожидаемая сумма в «центах» (или в той же единице, что и Price)
	}

	const (
		// Выбираем «большие», но безопасные значения, чтобы не вызвать overflow
		// в тестовой среде.  Если в реализации используется float64, то такие
		// числа всё равно помещаются без потери точности.
		largePrice   = int64(1_000_000_000) // 1 млрд единиц цены
		largeQty     = int64(2_000)         // 2 000 штук
		maxInt64     = int64(^uint64(0) >> 1)
		nearMaxInt64 = maxInt64 - 1_000_000 // немного ниже предела
	)

	tests := []testCase{
		{
			name: "zero_price_item",
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: 3, Price: 0},
				{ProductID: 2, Quantity: 2, Price: 1500},
			},
			expected: 3*0 + 2*1500,
		},
		{
			name: "zero_quantity_item",
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: 0, Price: 2000},
				{ProductID: 2, Quantity: 5, Price: 1200},
			},
			expected: 0*2000 + 5*1200,
		},
		{
			name: "large_values_no_overflow",
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: largeQty, Price: largePrice},
			},
			// 2 000 * 1 000 000 000 = 2 000 000 000 000
			expected: largeQty * largePrice,
		},
		{
			name: "near_max_int64_without_overflow",
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: 1, Price: nearMaxInt64},
			},
			expected: nearMaxInt64,
		},
		{
			name: "mixed_zero_and_normal_items",
			items: []entity.OrderItem{
				{ProductID: 1, Quantity: 4, Price: 0},
				{ProductID: 2, Quantity: 3, Price: 2500},
				{ProductID: 3, Quantity: 0, Price: 9999},
			},
			expected: 4*0 + 3*2500 + 0*9999,
		},
		{
			name: "duplicate_product_ids",
			items: []entity.OrderItem{
				{ProductID: 42, Quantity: 2, Price: 500},
				{ProductID: 42, Quantity: 3, Price: 500},
			},
			// 2*500 + 3*500 = 2500
			expected: 5 * 500,
		},
	}

	for _, tc := range tests {
		tc := tc // capture range variable
		t.Run(tc.name, func(t *testing.T) {
			// Каждый sub‑test получает «чистый» объект Order.
			o := entity.Order{
				CustomerID: 1,
				Items:      tc.items,
			}

			total := o.CalculateTotal()

			if total != tc.expected {
				t.Fatalf("unexpected total: got %d, want %d", total, tc.expected)
			}
		})
	}
}
```

### Что делает тест

| № | Сценарий | Что проверяется |
|---|----------|-----------------|
| 1 | `zero_price_item` | Цена `0` не влияет на итоговую сумму. |
| 2 | `zero_quantity_item` | Количество `0` не вносит вклад в сумму. |
| 3 | `large_values_no_overflow` | Суммирование больших чисел (1 млрд × 2 000) не приводит к переполнению. |
| 4 | `near_max_int64_without_overflow` | Сумма, близкая к `math.MaxInt64`, корректно считается. |
| 5 | `mixed_zero_and_normal_items` | Комбинация нулевых цен и количеств вместе с обычными позициями. |
| 6 | `duplicate_product_ids` | Метод не делает предположений о уникальности `ProductID` – просто суммирует. |

### Почему тест не дублирует существующие

* `TestUnitOrderCalculateTotal` проверяет обычный случай с несколькими позициями и положительными значениями.  
* `TestUnitOrderCalculateTotalEmpty` проверяет пустой список позиций.  

Новый тест покрывает **edge‑case‑ситуации**, которые в текущем наборе не проверяются: нулевые цены/количества, большие числа, дублирование `ProductID`.  

Все тесты используют **table‑driven** подход и **sub‑tests** (`t.Run`) – точно так же, как в остальных тестах проекта (см. `TestAPICategoryCRUD`, `TestUnitProductUCCreateValidatesCategory` и др.).  

После добавления этого файла `go test ./...` будет проходить без ошибок, а покрытие `entity.Order.CalculateTotal` будет расширено до 100 % (включая граничные условия).

