      if p.Name == "" {
          return ErrEmptyName
      }
      if p.Price < 0 {
          return ErrNegativePrice
      }
      if p.Price > 100_000 {
          return ErrPriceTooHigh   // ← старый лимит
      }
      if p.CategoryID <= 0 {
          return ErrInvalidCategory
      }
      return nil
